mapper.select:
SELECT plan_num, plan_qty, plan_status, plan_start, plan_end, emp_num, plan_id, item_num, item_name, type, ename, facility_num, facility_name, currentqty, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT pp.plan_num, pp.plan_id, pp.plan_qty, CASE WHEN pp.plan_status IN ('취소', '완료') THEN pp.plan_status WHEN pp.plan_status = '진행' THEN '진행' WHEN SYSDATE >= pp.plan_start THEN '진행' ELSE '대기' END AS plan_status, pp.plan_start, pp.plan_end, pp.emp_num, pp.item_num, i.name AS item_name, i.type, e.ename, f.facility_num, f.facility_name, NVL(wo.currentqty, 0) AS currentqty, COUNT(*) OVER() AS total_count FROM production_plan pp LEFT JOIN item i ON pp.item_num = i.item_num LEFT JOIN emp e ON pp.emp_num = e.emp_num LEFT JOIN ( SELECT item_num, facility_num FROM ( SELECT item_num, facility_num, ROW_NUMBER() OVER (PARTITION BY item_num ORDER BY flow) AS rn FROM process WHERE facility_num IS NOT NULL ) WHERE rn = 1 ) pr ON pp.item_num = pr.item_num LEFT JOIN facility f ON pr.facility_num = f.facility_num LEFT JOIN ( SELECT plan_num, SUM(current_qty) AS currentqty FROM work_order GROUP BY plan_num ) wo ON pp.plan_num = wo.plan_num
AND pp.plan_start >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND pp.plan_end <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND CASE WHEN pp.plan_status IN ('취소', '완료') THEN pp.plan_status WHEN pp.plan_status = '진행' THEN '진행' WHEN SYSDATE >= pp.plan_start THEN '진행' ELSE '대기' END = #{plan_status}
AND f.facility_num = #{facility_num}
AND pp.item_num = #{item_num}
AND i.type = #{item_type}
AND (pp.plan_id LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY pp.plan_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.update:
UPDATE production_plan
SET plan_status = #{plan_status}
WHERE plan_id = #{plan_id}
